const CONFIG = {
  AIRTABLE_PAT: $env.AIRTABLE_PAT || $env.AIRTABLE_API_KEY || "",
  AIRTABLE_BASE_ID: $env.AIRTABLE_BASE_ID || "",
  SHARED_API_KEY: $env.SHARED_API_KEY || "a58d49ae13d73706115681d14de53bd6857a88652b6cca8669a290898fcaac64",
  COMMENT_TABLE: $env.AIRTABLE_COMMENT_TABLE || "Comments",
  COMMENT_EPISODE_FIELD: $env.AIRTABLE_COMMENT_EPISODE_FIELD || "episode",
};

const headersIn = $json.headers || {};
if (String(headersIn["x-api-key"] || "") !== CONFIG.SHARED_API_KEY) {
  return { json: { statusCode: 401, body: { error: "unauthorized", code: "no_key" } } };
}
if (!String(headersIn["x-session-token"] || "").trim()) {
  return { json: { statusCode: 401, body: { error: "Session required", code: "session_missing" } } };
}
if (!CONFIG.AIRTABLE_PAT || !CONFIG.AIRTABLE_BASE_ID) {
  return { json: { statusCode: 500, body: { error: "Airtable config missing", code: "airtable_config_missing" } } };
}

const request = this.helpers.httpRequest.bind(this.helpers);
const airtable = "https://api.airtable.com/v0/" + CONFIG.AIRTABLE_BASE_ID;
const headers = { Authorization: "Bearer " + CONFIG.AIRTABLE_PAT };
const episodeId = String($json.params?.id || "").trim();
const bodyIn = $json.body || {};
const authorName = String(bodyIn.author_name || headersIn["x-user-name"] || "").trim().slice(0, 40);
const body = String(bodyIn.body || "").trim().slice(0, 800);
const authorRole = String(headersIn["x-user-role"] || "").trim();
const escapeFormulaString = (value) => String(value || "").replace(/'/g, "\\'");
const airtableStatus = (error) => Number(error?.statusCode || error?.status || error?.response?.statusCode || error?.response?.status || 0);
const airtableMessage = (error) => {
  const raw = error?.response?.body || error?.response?.data || error?.body || "";
  const payload = typeof raw === "string" ? raw : JSON.stringify(raw || {});
  return [error?.message || String(error), payload].filter(Boolean).join(" - ");
};

if (authorName.length < 2 || body.length < 2) {
  return { json: { statusCode: 400, body: { error: "Prenom et commentaire obligatoires", code: "comment_invalid" } } };
}

async function findEpisodeRecord(id) {
  if (!id) return null;
  try {
    return await request({ method: "GET", url: airtable + "/Episodes/" + encodeURIComponent(id), headers, json: true });
  } catch {}
  const formula = "OR(RECORD_ID() = '" + escapeFormulaString(id) + "', {id} = '" + escapeFormulaString(id) + "')";
  const data = await request({ method: "GET", url: airtable + "/Episodes?maxRecords=1&filterByFormula=" + encodeURIComponent(formula), headers, json: true });
  return data.records?.[0] || null;
}

const episode = await findEpisodeRecord(episodeId);
if (!episode) {
  return { json: { statusCode: 404, body: { error: "Episode not found", code: "episode_missing" } } };
}

let created;
try {
  created = await request({
    method: "POST",
    url: airtable + "/" + encodeURIComponent(CONFIG.COMMENT_TABLE),
    headers,
    body: {
      fields: {
        [CONFIG.COMMENT_EPISODE_FIELD]: [episode.id],
        author_name: authorName,
        author_role: authorRole,
        body,
      },
    },
    json: true,
  });
} catch (error) {
  const status = airtableStatus(error);
  const detail = airtableMessage(error);
  const permissionHint = status === 403 ? " Verifie que AIRTABLE_PAT a le scope data.records:write et acces a la base/table Comments." : "";
  return { json: { statusCode: status || 500, body: { error: "Airtable comment create failed: " + detail + permissionHint, code: status === 403 ? "airtable_comment_permission_denied" : "airtable_comment_create_failed" } } };
}

return {
  json: {
    statusCode: 200,
    body: {
      comment: {
        id: created.id,
        episode_id: episode.id,
        author_name: String(created.fields?.author_name || authorName),
        author_role: String(created.fields?.author_role || authorRole),
        body: String(created.fields?.body || body),
        created_at: String(created.createdTime || new Date().toISOString()),
      },
    },
  },
};
